+    #[test]
+    fn test_working_memory_capacity() {
+        // Note: capacity is clamped to 5-9 per Miller's Law (7±2)
+        let mut wm = WorkingMemory::new(5);
+        for i in 0..10 {
+            wm.add(
+                format!("item {}", i),
+                vec![i as f32; 4],
