+
+    #[test]
+    fn test_cosine_similarity() {
+        let a = vec![1.0, 0.0, 0.0];
+        let b = vec![1.0, 0.0, 0.0];
+        let c = vec![0.0, 1.0, 0.0];
+
+        assert!((cosine_similarity(&a, &b) - 1.0).abs() < 0.001);
+        assert!(cosine_similarity(&a, &c).abs() < 0.001);
+    }
