+                            .modified()
+                            .ok()
+                            .and_then(|t| {
+                                let dt: chrono::DateTime<chrono::Utc> = t.into();
+                                Some(dt.to_rfc3339())
+                            });
+                        (size, modified)
+                    })
+                    .unwrap_or((0, None));
+
+                results.push(FileInfo {
+                    path: path_str,
+                    is_dir: entry.file_type().is_dir(),
+                    size,
+                    modified_at,
+                });
+            }
+        }
+
+        results.sort_by(|a, b| a.path.cmp(&b.path));
+        results
+    }
+
+    /// Synchronous ls_info.
+    fn ls_info_sync(&self, path: &str) -> Vec<FileInfo> {
+        let resolved = match self.resolve_path(path) {
+            Ok(p) => p,
+            Err(_) => return Vec::new(),
+        };
+
+        let entries = match std::fs::read_dir(&resolved) {
+            Ok(e) => e,
+            Err(_) => return Vec::new(),
+        };
+
+        let mut results = Vec::new();
+        for entry in entries.flatten() {
+            let meta = match entry.metadata() {
+                Ok(m) => m,
+                Err(_) => continue,
+            };
+            let path_str = entry
+                .path()
+                .strip_prefix(&self.inner.cwd)
+                .unwrap_or(&entry.path())
+                .to_string_lossy()
+                .to_string();
+            let modified_at = meta
+                .modified()
+                .ok()
+                .map(|t| {
+                    let dt: chrono::DateTime<chrono::Utc> = t.into();
+                    dt.to_rfc3339()
+                });
+
+            results.push(FileInfo {
+                path: path_str,
+                is_dir: meta.is_dir(),
+                size: meta.len(),
+                modified_at,
+            });
+        }
+
+        results.sort_by(|a, b| a.path.cmp(&b.path));
+        results
+    }
+
+    /// Synchronous write_file.
+    fn write_file_sync(&self, file_path: &str, content: &str) -> WriteResult {
+        #[cfg(unix)]
+        {
+            // Use atomic resolve+open with TOCTOU protection
+            use std::io::Write;
+
+            let resolved = match self.resolve_path(file_path) {
+                Ok(p) => p,
+                Err(e) => {
+                    return WriteResult {
+                        error: Some(e.to_string()),
+                        path: None,
+                        files_update: None,
+                    };
+                }
+            };
+
+            // Create parent directories
+            if let Some(parent) = resolved.parent() {
+                if let Err(e) = std::fs::create_dir_all(parent) {
+                    return WriteResult {
+                        error: Some(format!("failed to create directories: {}", e)),
+                        path: None,
+                        files_update: None,
+                    };
+                }
+            }
+
+            match self.resolve_and_open(file_path, true) {
+                Ok(mut file) => {
+                    // Truncate file before writing
+                    if let Err(e) = file.set_len(0) {
+                        return WriteResult {
+                            error: Some(format!("failed to truncate file: {}", e)),
+                            path: None,
+                            files_update: None,
+                        };
+                    }
+
+                    match file.write_all(content.as_bytes()) {
+                        Ok(_) => WriteResult {
+                            error: None,
+                            path: Some(file_path.to_string()),
+                            files_update: None,
+                        },
+                        Err(e) => WriteResult {
+                            error: Some(e.to_string()),
+                            path: None,
+                            files_update: None,
+                        },
+                    }
+                }
+                Err(e) => WriteResult {
+                    error: Some(e.to_string()),
+                    path: None,
+                    files_update: None,
+                },
+            }
+        }
+
+        #[cfg(not(unix))]
+        {
+            // Fallback for non-Unix platforms
+            let resolved = match self.resolve_path(file_path) {
+                Ok(p) => p,
+                Err(e) => {
+                    return WriteResult {
+                        error: Some(e.to_string()),
+                        path: None,
+                        files_update: None,
+                    };
+                }
+            };
+
+            // Create parent directories
+            if let Some(parent) = resolved.parent() {
+                if let Err(e) = std::fs::create_dir_all(parent) {
+                    return WriteResult {
+                        error: Some(format!("failed to create directories: {}", e)),
+                        path: None,
+                        files_update: None,
+                    };
+                }
+            }
+
+            match std::fs::write(&resolved, content) {
+                Ok(_) => WriteResult {
+                    error: None,
+                    path: Some(file_path.to_string()),
+                    files_update: None,
+                },
+                Err(e) => WriteResult {
+                    error: Some(e.to_string()),
+                    path: None,
+                    files_update: None,
+                },
+            }
+        }
+    }
+
+    /// Synchronous edit_file.
+    fn edit_file_sync(
+        &self,
+        file_path: &str,
+        old_string: &str,
+        new_string: &str,
+        replace_all: bool,
+    ) -> EditResult {
+        let resolved = match self.resolve_path(file_path) {
+            Ok(p) => p,
+            Err(e) => {
+                return EditResult {
+                    error: Some(e.to_string()),
+                    path: None,
+                    files_update: None,
+                    occurrences: None,
+                };
+            }
+        };
+
+        let content = match std::fs::read_to_string(&resolved) {
+            Ok(c) => c,
+            Err(e) => {
+                return EditResult {
+                    error: Some(format!("failed to read file: {}", e)),
+                    path: Some(file_path.to_string()),
+                    files_update: None,
+                    occurrences: None,
+                };
+            }
+        };
+
+        let count = content.matches(old_string).count() as u32;
+        if count == 0 {
+            return EditResult {
+                error: Some(format!("old_string not found in {}", file_path)),
+                path: Some(file_path.to_string()),
+                files_update: None,
+                occurrences: Some(0),
+            };
+        }
+
+        if !replace_all && count > 1 {
+            return EditResult {
+                error: Some(format!(
+                    "old_string found {} times — must be unique (or use replace_all)",
+                    count
+                )),
+                path: Some(file_path.to_string()),
+                files_update: None,
+                occurrences: Some(count),
+            };
+        }
+
+        let new_content = if replace_all {
+            content.replace(old_string, new_string)
+        } else {
+            content.replacen(old_string, new_string, 1)
+        };
+
+        let replaced_count = if replace_all { count } else { 1 };
+
+        match std::fs::write(&resolved, &new_content) {
+            Ok(_) => EditResult {
+                error: None,
+                path: Some(file_path.to_string()),
+                files_update: None,
+                occurrences: Some(replaced_count),
+            },
+            Err(e) => EditResult {
+                error: Some(format!("failed to write file: {}", e)),
+                path: Some(file_path.to_string()),
+                files_update: None,
+                occurrences: Some(replaced_count),
+            },
+        }
+    }
+}
