+/// The full default middleware pipeline in execution order.
+/// (ADR-103 B3 amended ordering)
+const DEFAULT_MIDDLEWARE: &[&str] = &[
+    "todo",
+    "memory",
+    "skills",
+    "filesystem",
+    "subagent",
+    "summarization",
